<?php $__env->startSection('content'); ?><section class="dashboard-shell"><div class="container"><div class="dashboard-welcome"><div><span class="mini-label">Customer dashboard</span><h1>Payment history</h1><p class="section-lead">Razorpay transactions and booking references.</p></div><a class="btn btn-outline-party" href="<?php echo e(route('dashboard')); ?>">Back to dashboard</a></div><div class="dashboard-panel"><div class="table-responsive"><table class="table align-middle"><thead><tr><th>Date</th><th>Booking</th><th>Transaction</th><th>Method</th><th>Status</th><th>Amount</th></tr></thead><tbody><?php $__empty_1 = true; $__currentLoopData = $payments; $__env->addLoop($__currentLoopData); foreach($__currentLoopData as $payment): $__env->incrementLoopIndices(); $loop = $__env->getLastLoop(); $__empty_1 = false; ?><tr><td><?php echo e($payment->created_at->format('d M Y')); ?></td><td><a class="fw-bold" href="<?php echo e(route('dashboard.booking',$payment->booking)); ?>"><?php echo e($payment->booking->booking_no); ?></a></td><td><?php echo e($payment->payment_id ?: $payment->razorpay_order_id ?: '-'); ?></td><td><?php echo e(ucfirst($payment->method ?: 'Razorpay')); ?></td><td><span class="status-badge"><?php echo e($payment->payment_status); ?></span></td><td>&#8377;<?php echo e(number_format((float)$payment->amount)); ?></td></tr><?php endforeach; $__env->popLoop(); $loop = $__env->getLastLoop(); if ($__empty_1): ?><tr><td colspan="6" class="text-center py-5">No payment records yet.</td></tr><?php endif; ?></tbody></table></div><?php echo e($payments->links()); ?></div></div></section><?php $__env->stopSection(); ?>

